import{_ as l,c as n,o as r,a5 as i,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.52：Claude 3.5 Sonnet 支持、Bash 工具加载动画、大量桌面端改进","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.52.md","filePath":"changelog/v1.1.52.md","lastUpdated":1772014034000}'),t={name:"changelog/v1.1.52.md"};function o(s,e,d,h,c,p){return r(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="v1-1-52-claude-3-5-sonnet-支持、bash-工具加载动画、大量桌面端改进" tabindex="-1">v1.1.52：Claude 3.5 Sonnet 支持、Bash 工具加载动画、大量桌面端改进 <a class="header-anchor" href="#v1-1-52-claude-3-5-sonnet-支持、bash-工具加载动画、大量桌面端改进" aria-label="Permalink to “v1.1.52：Claude 3.5 Sonnet 支持、Bash 工具加载动画、大量桌面端改进”">​</a></h1><p><strong>发布日期</strong>：2026年02月05日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新启用了 Claude 3.5 Sonnet (new) 模型，TUI 新增 Bash 工具加载动画，修复了多个 provider 兼容性问题，桌面端大幅改进了终端稳定性和文件树同步。</p><hr><h2 id="新功能-claude-3-5-sonnet-new-模型支持" tabindex="-1">新功能：Claude 3.5 Sonnet (new) 模型支持 <a class="header-anchor" href="#新功能-claude-3-5-sonnet-new-模型支持" aria-label="Permalink to “新功能：Claude 3.5 Sonnet (new) 模型支持”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>启用了 Claude 3.5 Sonnet (new) 模型，可以直接在 OpenCode 中使用。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>如果你已经配置了 Anthropic API Key，可以在模型选择器中直接选择 Claude 3.5 Sonnet (new)。</p><hr><h2 id="新功能-bash-工具加载动画" tabindex="-1">新功能：Bash 工具加载动画 <a class="header-anchor" href="#新功能-bash-工具加载动画" aria-label="Permalink to “新功能：Bash 工具加载动画”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>TUI 中执行 Bash 命令时，现在会显示一个旋转加载动画，让你知道命令正在执行中。</p><h3 id="有什么用" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用" aria-label="Permalink to “有什么用？”">​</a></h3><p>之前执行耗时较长的命令时，界面看起来像是卡住了。现在有了加载动画，可以清楚地看到命令正在运行。</p><hr><h2 id="新功能-远程服务器终端连接" tabindex="-1">新功能：远程服务器终端连接 <a class="header-anchor" href="#新功能-远程服务器终端连接" aria-label="Permalink to “新功能：远程服务器终端连接”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>终端现在支持远程服务器连接，并修复了 GLIBC 兼容性问题。</p><h3 id="有什么用-1" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用-1" aria-label="Permalink to “有什么用？”">​</a></h3><p>如果你在远程服务器上使用 OpenCode 桌面端，终端连接更加稳定可靠。</p><hr><h2 id="新功能-thinking-blocks-快捷键绑定" tabindex="-1">新功能：Thinking Blocks 快捷键绑定 <a class="header-anchor" href="#新功能-thinking-blocks-快捷键绑定" aria-label="Permalink to “新功能：Thinking Blocks 快捷键绑定”">​</a></h2><h3 id="这次更新了什么-3" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-3" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在可以将显示/隐藏 Thinking Blocks 的功能绑定到自定义快捷键。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><p>在配置文件中设置快捷键绑定：</p><p>👉 <strong>完整教程</strong>：<a href="/5-advanced/06b-keybinds.html">快捷键配置</a></p><hr><h2 id="问题修复" tabindex="-1">问题修复 <a class="header-anchor" href="#问题修复" aria-label="Permalink to “问题修复”">​</a></h2><h3 id="kimi-k2-5-图片读取" tabindex="-1">Kimi K2.5 图片读取 <a class="header-anchor" href="#kimi-k2-5-图片读取" aria-label="Permalink to “Kimi K2.5 图片读取”">​</a></h3><p>修复了使用 OpenAI 兼容 provider（如 Kimi K2.5）时无法读取图片的问题。</p><h3 id="代理命令失败导致崩溃" tabindex="-1">代理命令失败导致崩溃 <a class="header-anchor" href="#代理命令失败导致崩溃" aria-label="Permalink to “代理命令失败导致崩溃”">​</a></h3><p>修复了代理命令失败时导致配置初始化崩溃的问题，现在会静默忽略代理命令失败。</p><h3 id="github-copilot-插件-headers" tabindex="-1">GitHub Copilot 插件 Headers <a class="header-anchor" href="#github-copilot-插件-headers" aria-label="Permalink to “GitHub Copilot 插件 Headers”">​</a></h3><p>修复了 GitHub Copilot 插件在非 TUI 客户端中未正确设置 headers 的问题。</p><h3 id="插件安装方式" tabindex="-1">插件安装方式 <a class="header-anchor" href="#插件安装方式" aria-label="Permalink to “插件安装方式”">​</a></h3><p>修复了插件安装使用 <code>bun add</code> 导致的问题，改为直接操作 package.json。</p><h3 id="只读配置目录" tabindex="-1">只读配置目录 <a class="header-anchor" href="#只读配置目录" aria-label="Permalink to “只读配置目录”">​</a></h3><p>在只读配置目录中跳过依赖安装，避免权限错误。</p><hr><h2 id="改进-桌面端" tabindex="-1">改进：桌面端 <a class="header-anchor" href="#改进-桌面端" aria-label="Permalink to “改进：桌面端”">​</a></h2><h3 id="文件树实时同步" tabindex="-1">文件树实时同步 <a class="header-anchor" href="#文件树实时同步" aria-label="Permalink to “文件树实时同步”">​</a></h3><p>文件树现在与文件系统变更保持实时同步，不再出现文件状态不一致的问题。</p><h3 id="终端稳定性" tabindex="-1">终端稳定性 <a class="header-anchor" href="#终端稳定性" aria-label="Permalink to “终端稳定性”">​</a></h3><p>多项终端稳定性修复，包括 URL 处理、行尾处理等。</p><h3 id="会话选项" tabindex="-1">会话选项 <a class="header-anchor" href="#会话选项" aria-label="Permalink to “会话选项”">​</a></h3><p>会话选项移到了会话页面，操作更方便。新增了会话选项功能。</p><h3 id="工作区切换" tabindex="-1">工作区切换 <a class="header-anchor" href="#工作区切换" aria-label="Permalink to “工作区切换”">​</a></h3><p>切换项目时自动刷新工作区会话和文件内容，避免显示过期数据。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>想用 Claude 3.5 Sonnet (new)</td><td>✅ 推荐升级</td></tr><tr><td>使用 Kimi K2.5</td><td>✅ 推荐升级</td></tr><tr><td>桌面端用户</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',56),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Enable Claude 3.5 Sonnet (new) model support</li><li>Silently ignore proxy command failures to prevent config initialization crashes</li><li>Ensure GitHub Copilot plugin properly sets headers when used in clients other than TUI</li><li>Bundle GitLab auth plugin directly instead of dynamic install</li><li>Fix plugin installation to use direct package.json manipulation instead of bun add</li><li>Fix image reading with OpenAI-compatible providers like Kimi K2.5 (@zhming0)</li><li>Downgrade xai ai-sdk package due to errors</li><li>Revert model autocomplete feature using models.dev schema reference</li><li>Add models.dev schema reference for model autocomplete in opencode.json (@remorses)</li><li>Adjust task tool description and input to reduce tool call failures with GPT models</li><li>Wait for dependencies before loading custom tools and plugins</li><li>Allow the function to hide or show thinking blocks to be bound to a key (@ariane-emory)</li><li>Skip dependency installation in read-only configuration directories (@shantur)</li><li>Ensure Kimi for Coding plan has thinking enabled by default for k2p5 (@monotykamary)</li><li>Fixed Cloudflare Workers AI provider</li><li>Prevent random hangs in plugin installs when using HTTP proxy by adding --no-cache flag</li><li>Session errors when attachment file not found are now handled gracefully</li><li>Support remote server connections in terminal and fix GLIBC compatibility (@lucas-jo)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add running spinner to bash tool in TUI (@goniz)</li><li>Add hover states to question tool tabs (@maharshi365)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>File changes not always available in app</li><li>File tree kept in sync with filesystem changes</li><li>Add Bosnian locale (@edoedac0)</li><li>Fix terminal URL handling issues</li><li>Remove extra horizontal padding around prompt input on mobile (@Brendonovich)</li><li>Refresh workspace sessions when switching projects (@neriousy)</li><li>Fixed terminal URL handling in the application</li><li>Fix terminal end-of-line handling issues</li><li>Refresh file contents when changing workspaces to prevent stale data (@ParkerSm1th)</li><li>Derive terminal WebSocket URL from browser origin instead of hardcoded localhost (@0xdsqr)</li><li>Last turn changes rendered in review pane</li><li>Safety triangle for sidebar hover to prevent menu from closing</li><li>Clear comments on prompt submission</li><li>Fix e2e test action in app</li><li>Terminal hyperlink clicks now work correctly</li><li>Fix dated e2e tests in app</li><li>Don&#39;t show scroll-to-bottom button unnecessarily</li><li>File tree not staying in sync across projects/sessions</li><li>Move session options to the session page</li><li>Add session options to app</li><li>Opened tabs follow created session</li><li>Removed compression from RPM bundle to save 15 minutes in CI (@goniz)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const u=l(t,[["render",o]]);export{m as __pageData,u as default};
